<?php
namespace App\Repositories\Customers; use App\Models\Customers\Customer; use Illuminate\Contracts\Pagination\LengthAwarePaginator; use Illuminate\Database\Eloquent\Collection;
class CustomerRepository { /** @param array<string,mixed> $filters */ public function paginateForCompany(int $companyId,array $filters=[],int $perPage=15):LengthAwarePaginator{return Customer::query()->with(['groups.group','loyaltyAccount','insight'])->where('company_id',$companyId)->when($filters['search']??null,fn($q,$v)=>$q->where(fn($x)=>$x->where('display_name','like',"%{$v}%")->orWhere('phone','like',"%{$v}%")->orWhere('customer_number','like',"%{$v}%")))->when($filters['status']??null,fn($q,$v)=>$q->where('status',$v))->when($filters['type']??null,fn($q,$v)=>$q->where('customer_type',$v))->when($filters['group_id']??null,fn($q,$v)=>$q->whereHas('groups',fn($x)=>$x->where('customer_group_id',$v)))->when($filters['trashed']??null,fn($q)=>$q->onlyTrashed())->latest()->paginate($perPage)->withQueryString();} public function findForCompany(int $companyId,int $id,bool $trashed=false):Customer{return Customer::query()->with(['addresses','contacts','groups.group','loyaltyAccount.transactions','walletTransactions','returnSummary','insight','activities.user'])->where('company_id',$companyId)->when($trashed,fn($q)=>$q->withTrashed())->findOrFail($id);} /** @return Collection<int,Customer> */ public function top(int $companyId):Collection{return Customer::query()->with(['groups.group','insight'])->where('company_id',$companyId)->orderByDesc('total_purchase_amount')->limit(10)->get();} }
